module top_module(clk_in, clk_out);input clk_in;
	output reg clk_out;
	reg [2:0] unused_contador;

	integer set = 1;

	always @(posedge clk_in)
	begin
		if (set == 1)
		begin
			clk_out = 0;
			unused_contador = 3'b0;
			set = 0;
		end

		unused_contador = unused_contador+1;

		if (unused_contador == 3'd4)
		begin
			clk_out = ~clk_out;
			unused_contador = 3'd0;
		end

	end

endmodule
